#include <bits/stdc++.h>
using namespace std;
int t,tp,x;
int main(){
    scanf("%d",&t);
    while(t--){
        scanf("%d%d",&tp,&x);
        if(tp==1){
            if(x==1){
                puts("0");
                continue;
            }
            int sum=0;
            for(int i=2;i*i<=x;i++)
                while(x%i==0)
                    sum++,x/=i;
            if(x>1)
                sum++;
            printf("%d\n",sum-1);
        }else{
            printf("%llu\n",(unsigned long long)1<<x+1);
        }
    }
    return 0;
}
